import{_ as e,c as l,o as a,a as i}from"./app.50048430.js";const _=JSON.parse('{"title":"\u6570\u7EC4","description":"","frontmatter":{"title":"\u6570\u7EC4","date":"2017-06-15T00:00:00.000Z","tags":["JS"]},"headers":[{"level":2,"title":"\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4","slug":"\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4"},{"level":2,"title":"\u8BA4\u8BC6\u6570\u7EC4\u7684\u672C\u8D28","slug":"\u8BA4\u8BC6\u6570\u7EC4\u7684\u672C\u8D28"},{"level":2,"title":"\u4E0B\u6807","slug":"\u4E0B\u6807"},{"level":2,"title":"\u6570\u7EC4\u7684\u5E38\u89C1\u64CD\u4F5C","slug":"\u6570\u7EC4\u7684\u5E38\u89C1\u64CD\u4F5C"},{"level":3,"title":"\u6DFB\u52A0\u6570\u7EC4\u9879","slug":"\u6DFB\u52A0\u6570\u7EC4\u9879"},{"level":3,"title":"\u5220\u9664\u6570\u636E","slug":"\u5220\u9664\u6570\u636E"},{"level":3,"title":"\u5176\u4ED6\u64CD\u4F5C","slug":"\u5176\u4ED6\u64CD\u4F5C"},{"level":2,"title":"\u8BED\u6CD5\u8865\u5145","slug":"\u8BED\u6CD5\u8865\u5145"},{"level":3,"title":"in \u5173\u952E\u5B57","slug":"in-\u5173\u952E\u5B57"},{"level":3,"title":"for-in\u3001forEach \u5FAA\u73AF","slug":"for-in\u3001foreach-\u5FAA\u73AF"}],"relativePath":"js/Array.md","lastUpdated":1661210647000}'),p={name:"js/Array.md"},s=i(`<h1 id="\u6570\u7EC4" tabindex="-1">\u6570\u7EC4 <a class="header-anchor" href="#\u6570\u7EC4" aria-hidden="true">#</a></h1><p>\u6570\u7EC4\u7528\u4E8E\u5B58\u653E\u591A\u4E2A\u6570\u636E</p><h2 id="\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4" tabindex="-1">\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4 <a class="header-anchor" href="#\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4" aria-hidden="true">#</a></h2><ol><li><code>new Array(\u957F\u5EA6)</code></li></ol><p>\u957F\u5EA6\uFF0C\u6570\u7EC4\u91CC\u9762\u7684\u6570\u636E\u603B\u6570\uFF0C\u957F\u5EA6\u4E00\u5B9A\u662F\u4E00\u4E2A\u975E\u8D1F\u6B63\u6570</p><p>new Array(\u6570\u636E,\u6570\u636E,\u6570\u636E...)</p><p>\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4,\u5E76\u521D\u59CB\u5316\u5176\u6BCF\u4E00\u9879\u7684\u503C</p><p>\u6570\u7EC4\u9879: \u6570\u7EC4\u5176\u4E2D\u7684\u4E00\u9879\u6570\u636E</p><ol start="2"><li><code>[\u6570\u636E,\u6570\u636E,\u6570\u636E...]</code></li></ol><p>\u521B\u5EFA\u4E00\u4E2A\u6570\u7EC4,\u5E76\u521D\u59CB\u5316\u6BCF\u4E00\u9879\u7684\u503C</p><h2 id="\u8BA4\u8BC6\u6570\u7EC4\u7684\u672C\u8D28" tabindex="-1">\u8BA4\u8BC6\u6570\u7EC4\u7684\u672C\u8D28 <a class="header-anchor" href="#\u8BA4\u8BC6\u6570\u7EC4\u7684\u672C\u8D28" aria-hidden="true">#</a></h2><p>\u6570\u7EC4\u7684\u672C\u8D28\u662F\u4E00\u4E2A\u5BF9\u8C61</p><ul><li>length \u5C5E\u6027: \u6570\u7EC4\u7684\u957F\u5EA6,\u4F1A\u81EA\u52A8\u53D8\u5316,\u6700\u5927\u4E0B\u6807+1</li><li>\u6570\u5B57\u5B57\u7B26\u4E32\u5C5E\u6027: \u53EB\u505A\u4E0B\u6807,\u4E5F\u53EB\u505A\u7D22\u5F15,\u76F8\u5F53\u4E8E\u6570\u7EC4\u4E2D\u6BCF\u4E2A\u6570\u636E\u7684\u7F16\u53F7,\u4E0B\u6807\u4ECE 0 \u5F00\u59CB</li></ul><p>\u8FDE\u7EED\u4E0B\u6807\u7684\u53D6\u503C\u8303\u56F4\uFF1A0 \uFF5E length -1\uFF0C\u5982\u679C\u7ED9 length \u76F4\u63A5\u8D4B\u503C\uFF0C\u4F1A\u5BFC\u81F4\u6570\u7EC4\u53EF\u80FD\u88AB\u622A\u65AD</p><p>\u5B9E\u9645\u5F00\u53D1\u4E2D\uFF0C\u4E0D\u8981\u7ED9 length \u8D4B\u503C</p><h2 id="\u4E0B\u6807" tabindex="-1">\u4E0B\u6807 <a class="header-anchor" href="#\u4E0B\u6807" aria-hidden="true">#</a></h2><p>\u901A\u5E38\u60C5\u51B5\u4E0B\uFF0C\u4E0B\u6807\u662F\u8FDE\u7EED\u7684\uFF0C</p><p>\u4E0B\u6807\u4E0D\u8FDE\u7EED\u7684\u6570\u7EC4\uFF0C\u53EB\u505A\u7A00\u677E\u6570\u7EC4\u3002</p><h2 id="\u6570\u7EC4\u7684\u5E38\u89C1\u64CD\u4F5C" tabindex="-1">\u6570\u7EC4\u7684\u5E38\u89C1\u64CD\u4F5C <a class="header-anchor" href="#\u6570\u7EC4\u7684\u5E38\u89C1\u64CD\u4F5C" aria-hidden="true">#</a></h2><h3 id="\u6DFB\u52A0\u6570\u7EC4\u9879" tabindex="-1">\u6DFB\u52A0\u6570\u7EC4\u9879 <a class="header-anchor" href="#\u6DFB\u52A0\u6570\u7EC4\u9879" aria-hidden="true">#</a></h3><ul><li><code>\u6570\u7EC4[\u957F\u5EA6] = \u6570\u636E</code>\uFF1A\u5411\u6570\u7EC4\u672B\u5C3E\u6DFB\u52A0\u4E00\u9879\u6570\u636E</li><li><code>\u6570\u7EC4.push(\u6570\u636E)</code>\uFF1A\u5411\u6570\u7EC4\u672B\u5C3E\u6DFB\u52A0\u4E00\u9879\u6570\u636E</li><li><code>\u6570\u7EC4.unshift(\u6570\u636E)</code>\uFF1A\u5411\u6570\u7EC4\u8D77\u59CB\u4F4D\u7F6E\u6DFB\u52A0\u4E00\u9879\u6570\u636E\uFF0C\u4F1A\u5BFC\u81F4\u6570\u7EC4\u6BCF\u4E00\u9879\u7684\u4E0B\u6807\u5411\u540E\u79FB\u52A8</li><li><code>\u6570\u7EC4.splice(\u4E0B\u6807,0,\u6DFB\u52A0\u7684\u6570\u636E)</code>\uFF1A\u4ECE\u6307\u5B9A\u4E0B\u6807\u4F4D\u7F6E\u5F00\u59CB\uFF0C\u5220\u9664 0 \u4E2A\uFF0C\u7136\u540E\u5728\u8BE5\u4F4D\u7F6E\u63D2\u5165\u6DFB\u52A0\u7684\u6570\u636E\uFF0C\u5982\u679C\u4E0B\u6807\u8D85\u8FC7\u6570\u7EC4\u4E0B\u6807\u7684\u8303\u56F4\uFF0C\u5219\u6309\u7167\u8303\u56F4\u7684\u8FB9\u754C\u8FDB\u884C\u5904\u7406\u3002</li></ul><p>push\u3001unshift\u3001splice \u53EF\u4EE5\u6DFB\u52A0\u591A\u4E2A\u6570\u636E</p><h3 id="\u5220\u9664\u6570\u636E" tabindex="-1">\u5220\u9664\u6570\u636E <a class="header-anchor" href="#\u5220\u9664\u6570\u636E" aria-hidden="true">#</a></h3><ul><li><code>delete \u6570\u7EC4[\u4E0B\u6807]</code>\uFF1A</li></ul><p>\u8FD9\u79CD\u505A\u6CD5\u4E0D\u4F1A\u5BFC\u81F4\u6570\u7EC4\u5176\u4ED6\u7684\u5C5E\u6027\u53D1\u751F\u53D8\u5316\uFF0C\u56E0\u6B64\uFF0C\u8BE5\u505A\u6CD5\u4F1A\u5BFC\u81F4\u4EA7\u751F\u7A00\u677E\u6570\u7EC4\uFF0C\u6240\u4EE5\u4E0D\u63A8\u8350\u4F7F\u7528\u8BE5\u505A\u6CD5\u3002</p><ul><li><code>\u6570\u7EC4.pop()</code>\uFF1A</li></ul><p>\u5220\u9664\u6570\u7EC4\u7684\u6700\u540E\u4E00\u9879\uFF0C\u8BE5\u8868\u8FBE\u5F0F\u8FD4\u56DE\u6700\u540E\u4E00\u9879\u7684\u6570\u636E</p><ul><li><code>\u6570\u7EC4.shift()</code>\uFF1A</li></ul><p>\u5220\u9664\u6570\u7EC4\u7B2C\u4E00\u9879\uFF0C\u8BE5\u8868\u8FBE\u5F0F\u8FD4\u56DE\u7B2C\u4E00\u9879\u7684\u6570\u636E</p><ul><li><code>\u6570\u7EC4.splice(\u4E0B\u6807,\u5220\u9664\u7684\u6570\u91CF,\u6DFB\u52A0\u7684\u6570\u636E)</code>\uFF1A</li></ul><p>\u4ECE\u6307\u5B9A\u4E0B\u6807\u4F4D\u7F6E\u5F00\u59CB\uFF0C\u5220\u9664\u6307\u5B9A\u6570\u91CF\uFF0C\u7136\u540E\u5728\u8BE5\u4F4D\u7F6E\u63D2\u5165\u6DFB\u52A0\u7684\u6570\u636E\uFF0C\u5982\u679C\u4E0B\u6807\u8D85\u8FC7\u6570\u7EC4\u4E0B\u6807\u7684\u8303\u56F4\uFF0C\u5219\u6309\u7167\u8303\u56F4\u7684\u8FB9\u754C\u8FDB\u884C\u5904\u7406\u3002\u8BE5\u8868\u8FBE\u5F0F\u8FD4\u56DE\u4E00\u4E2A\u65B0\u6570\u7EC4\uFF0C\u65B0\u6570\u7EC4\u8BB0\u5F55\u88AB\u5220\u9664\u7684\u6570\u636E\u3002</p><h3 id="\u5176\u4ED6\u64CD\u4F5C" tabindex="-1">\u5176\u4ED6\u64CD\u4F5C <a class="header-anchor" href="#\u5176\u4ED6\u64CD\u4F5C" aria-hidden="true">#</a></h3><ul><li><code>\u6570\u7EC4.slice(\u8D77\u59CB\u4F4D\u7F6E\u4E0B\u6807\uFF0C\u7ED3\u675F\u4F4D\u7F6E\u4E0B\u6807)</code>\uFF1A</li></ul><p>\u5C06\u8D77\u59CB\u4F4D\u7F6E\u5230\u7ED3\u675F\u4F4D\u7F6E\u4E0B\u6807(\u7ED3\u675F\u4E0B\u6807\u53D6\u4E0D\u5230)\u7684\u6570\u636E\u5220\u9664\uFF0C\u8FD4\u56DE\u4E00\u4E2A\u65B0\u6570\u7EC4\uFF0C\u4E0D\u4F1A\u6539\u53D8\u539F\u6570\u7EC4\uFF1B</p><p>\u4E0B\u6807\u53EF\u4EE5\u662F\u8D1F\u6570\uFF0C\u5982\u679C\u662F\u8D1F\u6570\uFF0C\u5219\u4ECE\u6570\u7EC4\u7684\u672B\u5C3E\u5F00\u59CB\u8BA1\u7B97\u3002</p><p>\u5982\u679C\u4E0D\u5199\u7ED3\u675F\u4E0B\u6807\uFF0C\u5219\u76F4\u63A5\u53D6\u5230\u672B\u5C3E\u3002</p><ul><li><p>\u6570\u7EC4\u6E05\u7A7A</p><ul><li><code>\u6570\u7EC4.splice(0,\u6570\u7EC4.length)</code></li><li><code>\u6570\u7EC4.length = 0</code></li></ul></li><li><p>\u67E5\u627E\u6570\u7EC4\u4E2D\u67D0\u4E00\u9879\u7684\u4E0B\u6807</p><ul><li><p><code>\u6570\u7EC4.indexOf(\u6570\u636E)</code>\uFF1A</p><p>\u4ECE\u6570\u7EC4\u4E2D\u4F9D\u6B21\u67E5\u627E\u5BF9\u5E94\u7684\u6570\u636E\uFF0C\u67E5\u627E\u65F6\u4F7F\u7528\u4E25\u683C\u76F8\u7B49\u8FDB\u884C\u6BD4\u8F83\u3002\u627E\u5230\u7B2C\u4E00\u4E2A\u5339\u914D\u7684\u4E0B\u6807\uFF0C\u8FD4\u56DE\u3002<strong>\u6CE8\u610F\uFF1A\u5982\u679C\u6CA1\u6709\u627E\u5230\uFF0C\u5219\u8FD4\u56DE-1\uFF1B</strong></p></li><li><p><code>\u6570\u7EC4.laseIndexOf(\u6570\u636E)</code></p><p>\u529F\u80FD\u548C indexOf \u7C7B\u4F3C\uFF0C\u53EA\u662F\u67E5\u627E\u7684\u662F\u6700\u540E\u4E00\u4E2A\u5339\u914D\u7684\u4E0B\u6807</p></li></ul></li><li><p><code>\u6570\u7EC4.fill()</code></p><ul><li><p><code>\u6570\u7EC4.fill(\u6570\u636E)</code>\uFF1A</p><p>\u5C06\u6570\u7EC4\u7684\u6240\u6709\u9879\uFF0C\u586B\u5145\u4E3A\u6307\u5B9A\u7684\u6570\u636E</p></li><li><p><code>\u6570\u7EC4.fill(\u6570\u636E\uFF0C\u5F00\u59CB\u4E0B\u6807)</code>\uFF1A</p><p>\u5C06\u6570\u7EC4\u4ECE\u5F00\u59CB\u4E0B\u6807\uFF0C\u5230\u6570\u7EC4\u7684\u672B\u5C3E\uFF0C\u586B\u5145\u4E3A\u6307\u5B9A\u7684\u6570\u636E</p></li><li><p><code>\u6570\u7EC4.fill(\u6570\u636E\uFF0C\u5F00\u59CB\u4E0B\u6807\uFF0C\u7ED3\u675F\u4E0B\u6807)</code>\uFF1A</p><p>\u5C06\u6570\u7EC4\u4ECE\u5F00\u59CB\u4E0B\u6807\uFF0C\u5230\u6570\u7EC4\u7684\u7ED3\u675F\u4E0B\u6807(\u53D6\u4E0D\u5230)\uFF0C\u586B\u5145\u4E3A\u6307\u5B9A\u7684\u6570\u636E</p></li></ul></li></ul><h2 id="\u8BED\u6CD5\u8865\u5145" tabindex="-1">\u8BED\u6CD5\u8865\u5145 <a class="header-anchor" href="#\u8BED\u6CD5\u8865\u5145" aria-hidden="true">#</a></h2><h3 id="in-\u5173\u952E\u5B57" tabindex="-1">in \u5173\u952E\u5B57 <a class="header-anchor" href="#in-\u5173\u952E\u5B57" aria-hidden="true">#</a></h3><p>\u5224\u65AD\u67D0\u4E2A\u5C5E\u6027\u540D\u5728\u5BF9\u8C61\u4E2D\u5C5E\u5426\u5B58\u5728</p><p>\u5C5E\u6027\u540D in \u5BF9\u8C61</p><h3 id="for-in\u3001foreach-\u5FAA\u73AF" tabindex="-1">for-in\u3001forEach \u5FAA\u73AF <a class="header-anchor" href="#for-in\u3001foreach-\u5FAA\u73AF" aria-hidden="true">#</a></h3><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#89DDFF;">for</span><span style="color:#A6ACCD;"> (</span><span style="color:#C792EA;">var</span><span style="color:#A6ACCD;"> prop </span><span style="color:#89DDFF;">in</span><span style="color:#A6ACCD;"> \u5BF9\u8C61) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;">// \u5FAA\u73AF\u4F53</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>\u53D6\u51FA\u5BF9\u8C61\u7684\u6240\u6709\u5C5E\u6027\u540D\uFF0C\u6BCF\u6B21\u5FAA\u73AF\u5C06\u5176\u4E2D\u4E00\u4E2A\u5C5E\u6027\u540D\u8D4B\u503C\u7ED9\u53D8\u91CF prop\uFF0C\u8FD0\u884C\u5FAA\u73AF\u4F53\u3002</p>`,44),n=[s];function d(o,r,c,t,h,u){return a(),l("div",null,n)}const g=e(p,[["render",d]]);export{_ as __pageData,g as default};
